def make_header(lang: str) -> dict:
    return {
        "Project-Id-Version": "travel_pro 1.0",
        "Report-Msgid-Bugs-To": "",
        "POT-Creation-Date": NOW,
        "PO-Revision-Date": NOW,
        "Last-Translator": "Travel Pro Team",
        "Language-Team": lang,
        "Language": lang,
        "MIME-Version": "1.0",
        "Content-Type": "text/plain; charset=UTF-8",
        "Content-Transfer-Encoding": "8bit",
        "Plural-Forms": _plural_forms(lang),
    }


def _plural_forms(lang: str) -> str:
    if lang == "ru":
        return "nplurals=3; plural=(n%10==1 && n%100!=11 ? 0 : n%10>=2 && n%10<=4 && (n%100<10 || n%100>=20) ? 1 : 2);"
    if lang == "ja":
        return "nplurals=1; plural=0;"
    if lang in ("uz", "it", "es"):
        return "nplurals=2; plural=(n != 1);"
    return "nplurals=2; plural=(n != 1);"


def build_po(lang: str) -> polib.POFile:
    po = polib.POFile()
    po.metadata = make_header(lang)
    po.metadata_is_fuzzy = False

    for msgid, translations in T.items():
        msgstr = translations.get(lang, "")
        entry = polib.POEntry(msgid=msgid, msgstr=msgstr)
        po.append(entry)

    return po


def main():
    for lang in LANGUAGES:
        lang_dir = os.path.join(LOCALE_DIR, lang, "LC_MESSAGES")
        os.makedirs(lang_dir, exist_ok=True)

        po = build_po(lang)
        po_path = os.path.join(lang_dir, "django.po")
        po.save(po_path)
        print(f"  Saved  {po_path}")

        mo_path = os.path.join(lang_dir, "django.mo")
        po.save_as_mofile(mo_path)
        print(f"  Compiled {mo_path}")

    print(f"\nDone — {len(T)} strings × {len(LANGUAGES)} languages")


if __name__ == "__main__":
    main()
